mapper.select:
/* SiteInfoMapper.selectSiteList - 현장목록 조회 */
SELECT s.* FROM site_info s WHERE s.del_yn = 'N' AND NOT EXISTS ( SELECT 1 FROM site_info c WHERE c.del_yn = 'N' AND c.parent_site_cd = s.site_cd )
order by site_name

/* SiteInfoMapper.getSiteInfoBySiteCd - 현장코드로 현장정보 조회 */
SELECT *
 FROM site_info
WHERE site_cd = #{siteCd}
 AND del_yn = 'N'
LIMIT 1

/* SiteInfoMapper.selectSiteListByParent - 부모 현장코드 기준 자식 현장목록 조회 */
SELECT s.*
FROM site_info s
WHERE s.del_yn = 'N'
AND (
s.site_cd IN

    #{siteCd}

OR s.parent_site_cd IN

    #{siteCd}

)
ORDER BY s.site_name

/* SiteInfoMapper.selectAllSite - 전체 현장코드 조회 */

select b.site_cd
from admin_user_site a join site_info b on a.site_cd = b.site_cd and b.del_yn = 'N'
where user_id =  #{adminId}
order by site_name
